### Шаг 3: Реализация системы сборки (`gulpfile.js`)

Ниже представлен полный код `gulpfile.js`. Он реализует логику генерации, обработки и сборки.

```javascript
const { src, dest, series, parallel, watch } = require('gulp');
const plumber = require('gulp-plumber');
const rename = require('gulp-rename');
const concat = require('gulp-concat');
const uglify = require('gulp-uglify');
const del = require('del');
const fs = require('fs');
const path = require('path');

// Конфигурация путей
const paths = {
    src: {
        specs: 'src/specs/*.json',
        templates: 'src/templates/*.template.html',
        scripts: 'src/scripts/*.js'
    },
    dist: {
        base: 'public',
        parsers: 'public/generated/parsers',
        views: 'public/views',
        scripts: 'public/assets/js',
        styles: 'public/assets/css'
    }
};

// 1. Очистка папки сборки
function clean() {
    return del([paths.dist.base]);
}

// 2. Генерация парсера из спецификации
// В реальном проекте здесь был бы вызов библиотеки типа pegjs или jison
function generateParser() {
    return src(paths.src.specs)
        .pipe(plumber())
        .pipe(require('gulp-foreach')((file, cb) => {
            // Симуляция генерации кода парсера на основе JSON
            const spec = JSON.parse(file.contents.toString());
            const parserCode = `
// Автогенерируемый парсер на основе ${spec.name}
// Дата генерации: ${new Date().toISOString()}

const ${spec.name}Parser = {
    parse: function(input) {
        // Логика парсинга, сгенерированная из спецификации
        console.log('Parsing input with ${spec.name}...');
        return input;
    },
    version: '${spec.version || '1.0.0'}'
};

module.exports = ${spec.name}Parser;
            `;

            // Записываем сгенерированный код в буфер файла
            file.contents = Buffer.from(parserCode);
            file.extname = '.js';
            cb(null, file);
        }))
        .pipe(rename({ prefix: 'gen_' }))
        .pipe(dest(paths.dist.parsers));
}

// 3. Обработка шаблонов (рендеринг)
// Симуляция рендеринга шаблона в статический HTML
function processTemplates() {
    return src(paths.src.templates)
        .pipe(plumber())
        .pipe(require('gulp-foreach')((file, cb) => {
            let content = file.contents.toString();

            // Простая замена плейсхолдеров (в реальности используйте EJS, Handlebars)
            content = content.replace('{{APP_TITLE}}', 'Мой Веб-Проект');
            content = content.replace('{{BUILD_DATE}}', new Date().toLocaleDateString());
            content = content.replace('{{PARSER_PATH}}', '../generated/parsers/gen_parser.js');

            file.contents = Buffer.from(content);
            file.extname = '.html';
            cb(null, file);
        }))
        .pipe(dest(paths.dist.views));
}

// 4. Сборка и минификация скриптов
function buildScripts() {
    return src(paths.src.scripts)
        .pipe(plumber())
        .pipe(concat('bundle.js'))
        .pipe(uglify())
        .pipe(dest(paths.dist.scripts));
}

// 5. Копирование статических ассетов (если есть)
function copyAssets() {
    return src('src/assets/**/*')
        .pipe(dest(paths.dist.base + '/assets'));
}

// 6. Создание финальной структуры (если нужны дополнительные файлы)
function createPublicStructure() {
    // Создаем файл конфигурации для продакшена
    const configContent = JSON.stringify({
        environment: 'production',
        parsers: ['gen_parser.js'],
        views: ['index.html'],
        scripts: ['bundle.js']
    }, null, 2);

    return src('package.json') // Берем за основу, но можно и вручную
        .pipe(rename('config.json'))
        .pipe(dest(paths.dist.base));
}

// Основной пайплайн
const build = series(
    clean,
    parallel(generateParser, processTemplates, buildScripts),
    copyAssets,
    createPublicStructure
);

// Режим разработки с наблюдением
function watchFiles() {
    watch(paths.src.specs, generateParser);
    watch(paths.src.templates, processTemplates);
    watch(paths.src.scripts, buildScripts);
}

// Экспорт задач
exports.clean = clean;
exports.generateParser = generateParser;
exports.processTemplates = processTemplates;
exports.buildScripts = buildScripts;
exports.build = build;
exports.default = series(build, watchFiles);
```

